SELECT AVG(percentage_blue) AS avg_percentage_blue
FROM color_tests
WHERE confidence_id = 1;

SELECT confidence_level
FROM confidence_levels
WHERE description = 'Very confident';

SELECT COUNT(session_id) AS session_count
FROM color_sessions
WHERE worker_id = 1;

SELECT role, COUNT(worker_id) AS total_workers, GROUP_CONCAT(worker_name) AS worker_names
FROM workers
GROUP BY role;
